              "ALT_Mounting:mount": {
                "displayName": "Разрешения для /bin/mount и /bin/umount",
                "help": "Эта политика определяет разрешения для /bin/mount и /bin/umount\n\nЛюбой пользователь — любому пользователю разрешено запускать /bin/mount и /bin/umount\n\nТолько wheel — пользователям из группы «wheel» разрешено запускать /bin/mount и /bin/umount\n\nНепривилегированный режим — любой пользователь может запускать /bin/mount и /bin/umount для непривилегированных действий (не от имени root)\n\nТолько root — только суперпользователю (root) разрешено запускать /bin/mount и /bin/umount",
                "header": {
                  "class": "Machine",
                  "name": "mount",
                  "displayName": "Разрешения для /bin/mount и /bin/umount",
                  "explainText": "Эта политика определяет разрешения для /bin/mount и /bin/umount\n\nЛюбой пользователь — любому пользователю разрешено запускать /bin/mount и /bin/umount\n\nТолько wheel — пользователям из группы «wheel» разрешено запускать /bin/mount и /bin/umount\n\nНепривилегированный режим — любой пользователь может запускать /bin/mount и /bin/umount для непривилегированных действий (не от имени root)\n\nТолько root — только суперпользователю (root) разрешено запускать /bin/mount и /bin/umount",
                  "key": "Software\\BaseALT\\Policies\\Control",
                  "valueName": null,
                  "presentation": "$(presentation.mount)",
                  "parentCategory": "system:ALT_Mounting",
                  "supportedOn": "8 Платформа ALT как минимум"
                },
                "Software\\BaseALT\\Policies\\Control\\mount": {
                  "metadata": {
                    "type": "enum",
                    "id": "mount_setter",
                    "valueName": "mount",
                    "required": true,
                    "items": {
                      "public": "Любой пользователь",
                      "wheelonly": "Только wheel",
                      "unprivileged": "Непривилегированный режим",
                      "restricted": "Только root"
                    },
                    "label": "Кому разрешено выполнять:",
                    "defaultItem": "0"
                  },
                  "data": "Read_Path_GPT('Software\\BaseALT\\Policies\\Control\\mount')"
                },
                "id": "ALT_Mounting:mount"
              },
