                        "valueName": "FocusPolicy",
                        "required": true,
                        "items": {
                          "FocusFollowMouse": "Фокус по щелчку",
                          "FocusFollowsMouse": "Фокус следует за мышью",
                          "FocusUnderMouse": "Фокус под мышью",
                          "FocusStrictlyUnderMouse": "Фокус строго под мышью"
                        },
                        "label": "Возможные режимы:",
